// Parse LLM response → slides array
const response = $input.first().json;
const text = response.candidates?.[0]?.content?.parts?.[0]?.text || '[]';

try {
  const slides = JSON.parse(text);
  return [{ json: { section_slides: Array.isArray(slides) ? slides : [slides] } }];
} catch (e) {
  // Try to extract JSON from text
  const match = text.match(/\[.*\]/s);
  if (match) {
    try {
      return [{ json: { section_slides: JSON.parse(match[0]) } }];
    } catch (e2) {}
  }
  return [{ json: { section_slides: [], parse_error: e.message } }];
}

// Prepare output for next pipeline
const merged = $input.first().json;
return [{
  json: {
    job_id: $('Start').first().json.job_id,
    slides: merged.slides,
    total_slides: merged.total_slides,
    context: $('Start').first().json.analyst_result
  }
}];
